import{_ as a,c as o,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Registro de Cambios: Historial de Versiones | opencode-md-table-formatter","description":"Conoce la evolución de versiones y las nuevas características de opencode-md-table-formatter. Consulta las características de v0.1.0, incluyendo formato automático y caché de ancho.","frontmatter":{"title":"Registro de Cambios: Historial de Versiones | opencode-md-table-formatter","sidebarTitle":"Resumen de Cambios de Versión","subtitle":"Registro de Cambios: Historial de Versiones y Registro de Cambios","description":"Conoce la evolución de versiones y las nuevas características de opencode-md-table-formatter. Consulta las características de v0.1.0, incluyendo formato automático y caché de ancho.","tags":["changelog","version-history","release-notes"],"prerequisite":[],"order":90},"headers":[],"relativePath":"es/franlol/opencode-md-table-formatter/changelog/release-notes/index.md","filePath":"es/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"}'),r={name:"es/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"};function t(n,e,l,c,d,m){return i(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="registro-de-cambios-historial-de-versiones-y-registro-de-cambios" tabindex="-1">Registro de Cambios: Historial de Versiones y Registro de Cambios <a class="header-anchor" href="#registro-de-cambios-historial-de-versiones-y-registro-de-cambios" aria-label="Permalink to &quot;Registro de Cambios: Historial de Versiones y Registro de Cambios&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Lo Que Aprenderás</p><ul><li>Seguir la evolución de versiones del plugin</li><li>Conocer las nuevas características y correcciones de cada versión</li><li>Dominar las limitaciones conocidas y detalles técnicos</li><li>Conocer las posibles mejoras futuras</li></ul></div><hr><h2 id="_0-1-0-2025-01-07" tabindex="-1">[0.1.0] - 2025-01-07 <a class="header-anchor" href="#_0-1-0-2025-01-07" aria-label="Permalink to &quot;[0.1.0] - 2025-01-07&quot;">​</a></h2><h3 id="nuevas-caracteristicas" tabindex="-1">Nuevas Características <a class="header-anchor" href="#nuevas-caracteristicas" aria-label="Permalink to &quot;Nuevas Características&quot;">​</a></h3><p>Esta es la <strong>versión inicial</strong> de opencode-md-table-formatter, que incluye las siguientes características principales:</p><ul><li><strong>Formato automático de tablas</strong>: Formatea automáticamente las tablas Markdown generadas por IA a través del hook <code>experimental.text.complete</code></li><li><strong>Soporte de modo oculto</strong>: Maneja correctamente los símbolos Markdown ocultos (como <code>**</code>, <code>*</code>) al calcular el ancho</li><li><strong>Procesamiento de Markdown anidado</strong>: Admite sintaxis Markdown anidada de profundidad arbitraria, utilizando un algoritmo de eliminación de múltiples pasadas</li><li><strong>Protección de bloques de código</strong>: Los símbolos Markdown dentro del código en línea (<code>`code`</code>) se mantienen en forma literal y no participan en el cálculo del ancho</li><li><strong>Soporte de alineación</strong>: Admite alineación a la izquierda (<code>---</code> o <code>:---</code>), alineación centrada (<code>:---:</code>), alineación a la derecha (<code>---:</code>)</li><li><strong>Optimización de caché de ancho</strong>: Almacena en caché los resultados de cálculo del ancho de visualización de cadenas, mejorando el rendimiento</li><li><strong>Validación de tablas inválidas</strong>: Valida automáticamente la estructura de la tabla, las tablas inválidas agregarán comentarios de error</li><li><strong>Soporte de múltiples caracteres</strong>: Admite Emoji, caracteres Unicode, celdas vacías, contenido muy largo</li><li><strong>Manejo silencioso de errores</strong>: El fallo de formato no interrumpirá el flujo de trabajo de OpenCode</li></ul><h3 id="detalles-tecnicos" tabindex="-1">Detalles Técnicos <a class="header-anchor" href="#detalles-tecnicos" aria-label="Permalink to &quot;Detalles Técnicos&quot;">​</a></h3><p>Esta versión contiene aproximadamente <strong>230 líneas de código TypeScript listo para producción</strong>:</p><ul><li><strong>12 funciones</strong>: Responsabilidades claras, buena separación</li><li><strong>Seguridad de tipos</strong>: Uso correcto de la interfaz <code>Hooks</code></li><li><strong>Limpieza inteligente de caché</strong>: Se activa cuando las operaciones superan 100 o las entradas de caché superan 1000</li><li><strong>Procesamiento de expresiones regulares de múltiples pasadas</strong>: Admite la eliminación de símbolos Markdown de profundidad de anidamiento arbitraria</li></ul><div class="tip custom-block"><p class="custom-block-title">Mecanismo de Caché</p><p>El caché está diseñado para optimizar el cálculo del ancho de contenido repetido. Por ejemplo, cuando el mismo texto de celda aparece varias veces en la tabla, el ancho se calcula solo una vez y las siguientes veces se lee directamente del caché.</p></div><h3 id="limitaciones-conocidas" tabindex="-1">Limitaciones Conocidas <a class="header-anchor" href="#limitaciones-conocidas" aria-label="Permalink to &quot;Limitaciones Conocidas&quot;">​</a></h3><p>Esta versión no admite los siguientes escenarios:</p><ul><li><strong>Tablas HTML</strong>: Solo admite tablas de tubería Markdown (Pipe Table)</li><li><strong>Celdas multilínea</strong>: No admite celdas que contengan etiquetas <code>&lt;br&gt;</code></li><li><strong>Tablas sin fila separadora</strong>: Las tablas deben contener una fila separadora (<code>|---|</code>) para ser formateadas</li><li><strong>Requisitos de dependencia</strong>: Requiere <code>@opencode-ai/plugin</code> &gt;= 0.13.7 (utiliza el hook no documentado <code>experimental.text.complete</code>)</li></ul><div class="info custom-block"><p class="custom-block-title">Requisitos de Versión</p><p>El plugin depende de OpenCode &gt;= 1.0.137 y <code>@opencode-ai/plugin</code> &gt;= 0.13.7 para funcionar correctamente.</p></div><hr><h2 id="planes-futuros" tabindex="-1">Planes Futuros <a class="header-anchor" href="#planes-futuros" aria-label="Permalink to &quot;Planes Futuros&quot;">​</a></h2><p>Las siguientes características están planificadas para implementarse en versiones futuras:</p><ul><li><strong>Opciones de configuración</strong>: Admite personalización de ancho mínimo/máximo de columnas, deshabilitar características específicas</li><li><strong>Soporte de tablas sin encabezado</strong>: Formatear tablas sin filas de encabezado</li><li><strong>Optimización de rendimiento</strong>: Análisis y optimización del rendimiento para tablas muy grandes (100+ filas)</li><li><strong>Más opciones de alineación</strong>: Ampliar la sintaxis y funcionalidad de alineación</li></ul><div class="tip custom-block"><p class="custom-block-title">Contribuir</p><p>Si tienes sugerencias de características o quieres contribuir código, bienvenido a plantear tus ideas en <a href="https://github.com/franlol/opencode-md-table-formatter/issues" target="_blank" rel="noreferrer">GitHub Issues</a>.</p></div><hr><h2 id="formato-del-registro-de-cambios" tabindex="-1">Formato del Registro de Cambios <a class="header-anchor" href="#formato-del-registro-de-cambios" aria-label="Permalink to &quot;Formato del Registro de Cambios&quot;">​</a></h2><p>El registro de cambios de este proyecto sigue el formato <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, y los números de versión siguen la especificación <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><p><strong>Formato del número de versión</strong>: <code>MAJOR.MINOR.PATCH</code></p><ul><li><strong>MAJOR</strong>: Cambios incompatibles en la API</li><li><strong>MINOR</strong>: Nuevas características compatibles con versiones anteriores</li><li><strong>PATCH</strong>: Correcciones de problemas compatibles con versiones anteriores</li></ul><p><strong>Tipos de cambios</strong>:</p><ul><li><strong>Added</strong>: Nuevas características</li><li><strong>Changed</strong>: Cambios en características existentes</li><li><strong>Deprecated</strong>: Características que se eliminarán pronto</li><li><strong>Removed</strong>: Características eliminadas</li><li><strong>Fixed</strong>: Correcciones de problemas</li><li><strong>Security</strong>: Correcciones relacionadas con seguridad</li></ul><hr><h2 id="orden-sugerido-de-lectura" tabindex="-1">Orden Sugerido de Lectura <a class="header-anchor" href="#orden-sugerido-de-lectura" aria-label="Permalink to &quot;Orden Sugerido de Lectura&quot;">​</a></h2><p>Si eres un nuevo usuario, se recomienda aprender en el siguiente orden:</p><ol><li><a href="./../../start/getting-started/">Comenzar en un Minuto: Instalación y Configuración</a> — Comenzar rápidamente</li><li><a href="./../../start/features/">Visión General de Características: La Magia del Formato Automático</a> — Conocer las características principales</li><li><a href="./../../faq/troubleshooting/">Preguntas Frecuentes: ¿Qué hacer si la tabla no se formatea?</a> — Solución de problemas</li><li><a href="./../../appendix/limitations/">Limitaciones Conocidas: ¿Dónde están los límites del plugin?</a> — Conocer las limitaciones</li></ol>',31)])])}const p=a(r,[["render",t]]);export{g as __pageData,p as default};
